def gen(rng, size):
    n = max(1, min(size, 100))
    if n == 1:
        s = str(rng.randint(0, 9))
    else:
        s = str(rng.randint(1, 9)) + ''.join(str(rng.randint(0, 9)) for _ in range(n - 1))
    return [s]

