class Solution:
    def minimumOperations(self, num):
        n = len(num)
        best_kept = 0
        for mask in range(1, 1 << n):
            chars = [num[i] for i in range(n) if mask & (1 << i)]
            val = int(''.join(chars))
            if val % 25 == 0:
                cnt = bin(mask).count('1')
                if cnt > best_kept:
                    best_kept = cnt
        return n - best_kept

