class Solution:
    def minimumOperations(self, num):
        n = len(num)
        patterns = [('0', '0'), ('2', '5'), ('5', '0'), ('7', '5')]
        best = -1
        for c0, c1 in patterns:
            found_c1 = False
            for i in range(n - 1, -1, -1):
                if num[i] == c0 and found_c1:
                    cand = i + 2
                    if cand > best:
                        best = cand
                    break
                if num[i] == c1:
                    found_c1 = True
        if best == -1:
            if '0' in num:
                return n - 1
            return n
        return n - best

