var minimumOperations = function(num) {
    const n = num.length;
    const patterns = [['0', '0'], ['2', '5'], ['5', '0'], ['7', '5']];
    let best = -1;
    for (const [c0, c1] of patterns) {
        let foundC1 = false;
        for (let i = n - 1; i >= 0; i--) {
            if (num[i] === c0 && foundC1) {
                const cand = i + 2;
                if (cand > best) best = cand;
                break;
            }
            if (num[i] === c1) foundC1 = true;
        }
    }
    if (best === -1) {
        if (num.includes('0')) return n - 1;
        return n;
    }
    return n - best;
};
